				SourceURL: source,
				LocalPath: localPath,
				LocalDir:  localDir,
				Ref:       ref,
				Commit:    commit,
				Floating:  floating,
				Scope:     scope,
				ActivationRoot: activationRoot,
				Targets:   targets,
			}
