		fmt.Fprintf(&b, "  local_path: %s\n", c.LocalPath)
	}
	if c.Ref != "" {
		fmt.Fprintf(&b, "  ref: %s\n", c.Ref)
	}
	if c.Commit != "" {
		fmt.Fprintf(&b, "  commit: %s\n", c.Commit)
	}
